import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function ProposalForm() {
  const { projectId } = useParams();
  const [project, setProject] = useState(null);
  const [formData, setFormData] = useState({
    cover_letter: '',
    bid_amount: '',
    estimated_days: ''
  });
  const navigate = useNavigate();

  // Wrap fetchProject in useCallback
  const fetchProject = useCallback(async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get(`http://127.0.0.1:8000/api/projects/${projectId}/`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProject(response.data);
    } catch (error) {
      console.error('Error fetching project:', error);
    }
  }, [projectId]);

  useEffect(() => {
    fetchProject();
  }, [fetchProject]);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('access');
      await axios.post('http://127.0.0.1:8000/api/proposals/create/', {
        project: projectId,
        ...formData
      }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      alert('Proposal submitted successfully!');
      navigate('/projects');
    } catch (error) {
      console.error('Error submitting proposal:', error);
      alert('Failed to submit proposal');
    }
  };

  if (!project) return <div>Loading...</div>;

  return (
    <div className="container">
      <h2>Submit Proposal</h2>
      <div className="project-summary">
        <h3>{project.title}</h3>
        <p><strong>Budget:</strong> ₹{project.budget_min} - ₹{project.budget_max}</p>
        <p><strong>Skills:</strong> {project.skills_required}</p>
      </div>

      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>Cover Letter:</label>
          <textarea
            name="cover_letter"
            value={formData.cover_letter}
            onChange={handleChange}
            required
            rows="5"
            placeholder="Explain why you're the best fit for this project..."
          />
        </div>

        <div className="form-group">
          <label>Bid Amount (₹):</label>
          <input
            type="number"
            name="bid_amount"
            value={formData.bid_amount}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Estimated Days:</label>
          <input
            type="number"
            name="estimated_days"
            value={formData.estimated_days}
            onChange={handleChange}
            required
          />
        </div>

        <button type="submit">Submit Proposal</button>
        <button type="button" onClick={() => navigate('/projects')}>Cancel</button>
      </form>
    </div>
  );
}

export default ProposalForm;
